import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote - base premiums and processing fee", () => {
    it.todo("empty item list yields premium 5 G (only the processing fee)");
    it.todo("a single plain sword (no modifiers, follow-up customer) yields base premium 100 G + 5 G fee");
    it.todo("a single plain amulet yields base premium 60 G + fee");
    it.todo("a single plain staff yields base premium 80 G + fee");
    it.todo("a single plain potion yields base premium 40 G + fee");
  });

  describe("quote - components and building blocks", () => {
    it.todo("2 runes yield 50 G base premium (25 each, no block)");
    it.todo("3 runes yield 60 G base premium (block applies)");
    it.todo("4 runes yield 100 G base premium (no block - block requires exactly 3)");
    it.todo("7 runes yield 175 G base premium (no block for any group of size != 3)");
    it.todo("2 runes + 1 moonstone yield 75 G base premium (no block: different types)");
    it.todo("3 runes + 3 moonstones yield 120 G base premium (two separate blocks)");
  });

  describe("quote - item-specific modifiers", () => {
    it.todo("a cursed sword adds 50% of the sword's base premium as curse surcharge");
    it.todo("a sword with enchantment exactly 5 adds the 30% high-enchantment surcharge");
    it.todo("a sword with enchantment 4 does not add the high-enchantment surcharge");
    it.todo("a cursed sword with enchantment 5 adds both curse and high-enchantment surcharges");
  });

  describe("quote - policy-wide modifiers", () => {
    it.todo("a customer with exactly 2 years with MHPCO gets the 20% loyalty discount");
    it.todo("a first insurance (customer's first contract) adds a 10% surcharge on the policy base");
    it.todo("a follow-up contract (not the first) applies a 15% discount on the policy base");
  });

  describe("quote - multi-item policies and modifier scope", () => {
    it.todo("a policy covering a cursed sword and a plain amulet yields policy base 160 G plus 50 G curse surcharge = 210 G before further modifiers and fee");
  });

  describe("quote - rounding", () => {
    it.todo("a premium calculation that yields 197.5 G is rounded up to 198 G");
  });

  describe("quote - integration examples", () => {
    it.todo("newcomer (0 years, no previous contract) with a cursed steel sword enchantment 3 yields premium 165 G");
    it.todo("3-year customer's second quote with a cursed steel sword enchantment 7 yields premium 160 G");
  });

  describe("claim - standard reimbursement and deductible", () => {
    it.todo("a regular sword (steel, enchantment 3) with 500 G damage yields payout 400 G");
    it.todo("damage to a rune (insurance value 250 G) of 200 G yields payout 100 G");
    it.todo("a dragon attack damaging an insured sword (500 G) and insured amulet (300 G) yields payout 600 G (deductible per damage event)");
  });

  describe("claim - special clauses", () => {
    it.todo("a steel sword with enchantment 9 and damage 1000 G yields payout 400 G (50% rule then deductible)");
    it.todo("a dragon-material sword with enchantment 5 and damage 800 G yields payout 700 G (dragon material full reimbursement then deductible)");
    it.todo("a dragon-material sword with enchantment 9 and damage 1000 G yields payout 400 G (50% rule wins, then deductible)");
    it.todo("a dragon-material sword with enchantment exactly 8 and damage 1000 G yields payout 400 G (high-enchantment clause then deductible)");
  });

  describe("claim - cap exhaustion", () => {
    it.todo("a policy covering a sword and an amulet has insurance sum 1600 G and cap 3200 G");
    it.todo("a cursed sword policy has cap 2000 G (based on unmodified insurance value)");
    it.todo("a policy with a sword and 3 runes has insurance sum 1750 G (block discount does not affect insurance sum)");
    it.todo("two successive 1500 G claims on a sword policy yield payouts 1400 G then 600 G (cap exhausted)");
  });

  describe("claim - multiple items of the same type", () => {
    it.todo("a policy covering two swords has insurance sum 2000 G and cap 4000 G");
    it.todo("a dragon attack damaging both insured swords treats each damage entry as separate with its own deductible");
  });

  describe("claim - rounding", () => {
    it.todo("a payout calculation yielding 350.5 G is rounded down to 350 G");
  });
});

